#include<cstdio>
#include<cstring>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> T max(const T &x,const T &y){return x<y?y:x;}
template<typename T> T min(const T &x,const T &y){return x<y?x:y;}
const int N=2.5e5+10,M=5e5+10;int head[N],des[M],nxt[M],cgt,val[M];LL dp[N];
const int INF=0x3f3f3f3f;const LL Infll=1e16;
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
inline void ins(const int &z,const int &x,const int &y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;val[cgt]=z;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;val[cgt]=z;
}
int ql[N],top[N],fa[N],dep[N],siz[N],mxs[N],n,cdt,k,mxv[N];
int st[N][20],Lg[N];inline void Init()
{
	Lg[0]=-1;rep(1,n,i)Lg[i]=Lg[i>>1]+1;
	rep(1,Lg[n],j)rep(1,n-(1<<j)+1,i)st[i][j]=min(st[i][j-1],st[i+(1<<(j-1))][j-1]);
}
inline int qry(const int &l,const int &r){int len=Lg[r-l+1];return min(st[l][len],st[r-(1<<len)+1][len]);}
inline void dfs1(int u=1,int f=0)
{
	dep[u]=dep[f]+1;siz[u]=1;fa[u]=f;int mx=0;
	grep(u,i)if(des[i]!=f)
	{
		int v=des[i];dfs1(v,u);siz[u]+=siz[v];
		siz[v]>mx?mx=siz[v],mxs[u]=v,mxv[u]=val[i]:0;
	}
}
inline void dfs2(int u=1,int fa=0,int tp=1,int vl=0)
{
	st[ql[u]=++cdt][0]=vl;top[u]=tp;mxs[u]?dfs2(mxs[u],u,tp,mxv[u]):void();
	grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u]){int v=des[i];dfs2(v,u,v,val[i]);}
}
inline int LCA(int x,int y)
{
	while(top[x]!=top[y])dep[top[x]]<dep[top[y]]?y=fa[top[y]]:x=fa[top[x]];
	return dep[x]<dep[y]?x:y;
}
inline int Val(const int &x,int y)
{
	int res=INF;while(top[x]!=top[y])res=min(res,qry(ql[top[y]],ql[y])),y=fa[top[y]];
	return x==y?res:min(res,qry(ql[x]+1,ql[y]));
}
inline bool cmp(const int &x,const int &y){return ql[x]<ql[y];}
#define frep(b,c) for(int c=fhead[(b)];c;c=fnxt[c])
int fhead[N],fnxt[N],fdes[N],fcgt,mrk[N],stk[M],fstk[M],ftop;bool vis[N];LL fval[N];
inline void fins(const int &x,const int &y,const int &z){fstk[++ftop]=x;fnxt[++fcgt]=fhead[x];fdes[fhead[x]=fcgt]=y;fval[fcgt]=z;}
inline void Back(){while(ftop)fhead[fstk[ftop--]]=0;}
inline void DP(int u=1,int fa=0)
{
	if(vis[u])return dp[u]=INF,void();dp[u]=0;
	frep(u,i)if(fdes[i]!=fa){int v=fdes[i];DP(v,u);dp[u]+=min(dp[v],fval[i]);}
}
inline void Build()
{
	fcgt=0;int top=stk[1]=1;
	rep(2,k,i)
	{
		int u=mrk[i],lc=LCA(u,stk[top]);
		while(dep[stk[top-1]]>dep[lc])fins(stk[top-1],stk[top],Val(stk[top-1],stk[top])),--top;
		if(lc!=stk[top]){fins(lc,stk[top],Val(lc,stk[top]));lc!=stk[top-1]?stk[top]=lc:--top;}
		stk[++top]=u;
	}
	while(top)if(--top)fins(stk[top],stk[top+1],Val(stk[top],stk[top+1]));
}
int main()
{
	n=read();rep(2,n,i)ins(read(),read(),read());
	dfs1();dfs2();Init();int M=read();while(M--)
	{
		k=read()+1;mrk[1]=1;rep(2,k,i)vis[mrk[i]=read()]=true;
		std::sort(mrk+2,mrk+k+1,cmp);Build();DP();printf("%lld\n",dp[1]);
		rep(1,k,i)vis[mrk[i]]=false;Back();
	}
}
